namespace TestExpert.WPF.Models;
public class ExamAttempt { public int Id { get; set; } public int StudentId { get; set; } public User Student { get; set; } = null!; public int ExamId { get; set; } public Exam Exam { get; set; } = null!; public DateTime StartedAt { get; set; } = DateTime.Now; public DateTime? FinishedAt { get; set; } public double Score { get; set; } public double MaxScore { get; set; } public string Status { get; set; } = "InProgress"; public int AttemptNumber { get; set; } = 1; public ICollection<AttemptAnswer> Answers { get; set; } = new List<AttemptAnswer>(); }
